#include <bits/stdc++.h>
#include <algorithm>
using namespace std;

int main(){
	int n,na,nb;
	cin>>n>>na>>nb;
	int za[na],zb[nb]; 
	
	for(int i=0;i<na;i++){
		cin>>za[i];
	}
	for(int i=0;i<nb;i++){
		cin>>zb[i];
	}
	int sa=0,sb=0;
	for(int i=0;i<n;i++){

		int a = za[i%na];
		int b = zb[i%nb];
		if(a==0){
			if(b==1)sb++;
			if(b==2)sa++;
			if(b==3)sa++;
			if(b==4)sb++;
		}

		if(a==1){
			if(b==0)sa++;
			if(b==2)sb++;
			if(b==3)sa++;
			if(b==4)sb++;
		}
		if(a==2){
			if(b==0)sb++;
			if(b==1)sa++;
			if(b==3)sb++;
			if(b==4)sa++;
		}
		if(a==3){
			if(b==0)sb++;
			if(b==1)sb++;
			if(b==2)sa++;
			if(b==4)sa++;
		}
		if(a==4){
			if(b==0)sa++;
			if(b==1)sa++;
			if(b==2)sb++;
			if(b==3)sb++;	
		}
		
	}
	cout<<sa<<' '<<sb;
	
}
